import { describe, expect, it } from 'vitest';

import { resolveAgenticMode } from '../openai-agentic-mode';

describe('OpenAI agentic mode resolution', () => {
  it('defaults to bare mode when no header, body flag, or env default is set', () => {
    expect(resolveAgenticMode({}).enabled).toBe(false);
  });

  it('lets the X-Zedge-Agentic header opt into or force out of tools', () => {
    expect(
      resolveAgenticMode({
        headers: { 'x-zedge-agentic': 'tools' },
      }),
    ).toEqual({ enabled: true, source: 'header' });

    expect(
      resolveAgenticMode({
        headers: { 'x-zedge-agentic': 'off' },
        request: { auto_tools: true },
      }),
    ).toEqual({ enabled: false, source: 'header' });
  });

  it('uses request flags when headers are absent', () => {
    expect(resolveAgenticMode({ request: { auto_tools: true } })).toEqual({
      enabled: true,
      source: 'body',
    });

    expect(resolveAgenticMode({ request: { tool_choice: 'none' } })).toEqual({
      enabled: false,
      source: 'body',
    });
  });

  it('passes through MCP URL overrides from headers or body', () => {
    expect(
      resolveAgenticMode({
        headers: {
          'x-zedge-agentic': 'true',
          'x-zedge-mcp-url': 'http://127.0.0.1:7331/mcp',
        },
      }),
    ).toEqual({
      enabled: true,
      source: 'header',
      mcpUrl: 'http://127.0.0.1:7331/mcp',
    });

    expect(
      resolveAgenticMode({
        request: {
          auto_tools: true,
          mcp_url: 'http://companion.test/mcp',
        },
      }),
    ).toEqual({
      enabled: true,
      source: 'body',
      mcpUrl: 'http://companion.test/mcp',
    });
  });
});
